import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useAuth } from '../context/AuthContext';
import '../styles/Navbar.css';

const Navbar = () => {
    const { isAuthenticated, user, logout, isAdmin } = useAuth();
    const [isOpen, setIsOpen] = useState(false);

    const menuVariants = {
        hidden: { opacity: 0, y: -20 },
        visible: {
            opacity: 1,
            y: 0,
            transition: { staggerChildren: 0.1, delayChildren: 0.2 }
        }
    };

    const itemVariants = {
        hidden: { opacity: 0, x: -10 },
        visible: { opacity: 1, x: 0 }
    };

    return (
        <motion.nav 
            className="navbar"
            initial={{ y: -100 }}
            animate={{ y: 0 }}
            transition={{ duration: 0.5 }}
        >
            <div className="navbar-container">
                <motion.div whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.95 }}>
                    <Link to="/" className="logo">🏠 RealEstateHub</Link>
                </motion.div>

                <motion.div className="nav-menu" variants={menuVariants} initial="hidden" animate="visible">
                    <motion.div variants={itemVariants}>
                        <Link to="/properties" className="nav-link">Properties</Link>
                    </motion.div>
                    <motion.div variants={itemVariants}>
                        <Link to="/about" className="nav-link">About</Link>
                    </motion.div>
                    <motion.div variants={itemVariants}>
                        <Link to="/contact" className="nav-link">Contact</Link>
                    </motion.div>
                    {isAuthenticated && (
                        <>
                            <motion.div variants={itemVariants}>
                                <Link to="/property/create" className="nav-link highlight">Add Property</Link>
                            </motion.div>
                            <motion.div variants={itemVariants}>
                                <Link to="/my-bookings" className="nav-link">My Bookings</Link>
                            </motion.div>
                            <motion.div variants={itemVariants}>
                                <Link to="/manage-listings" className="nav-link">Manage Listings</Link>
                            </motion.div>
                            <motion.div variants={itemVariants}>
                                <Link to="/profile" className="nav-link">Profile</Link>
                            </motion.div>
                            {isAdmin && (
                                <motion.div variants={itemVariants}>
                                    <Link to="/admin" className="nav-link admin-link">
                                        👑 Admin
                                    </Link>
                                </motion.div>
                            )}
                        </>
                    )}
                </motion.div>

                <motion.div className="nav-auth">
                    {isAuthenticated ? (
                        <div className="auth-group">
                            <motion.span 
                                className="user-name"
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                transition={{ delay: 0.3 }}
                            >
                                ✋ {user?.name}
                            </motion.span>
                            <motion.button 
                                onClick={logout} 
                                className="logout-btn"
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.95 }}
                            >
                                Logout
                            </motion.button>
                        </div>
                    ) : (
                        <div className="auth-group">
                            <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                                <Link to="/login" className="login-btn">Login</Link>
                            </motion.div>
                            <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                                <Link to="/register" className="register-btn">Register</Link>
                            </motion.div>
                        </div>
                    )}
                </motion.div>
            </div>
        </motion.nav>
    );
};

export default Navbar;
